int _recoveryTaskEstimateSize(
  RecoveryTask object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.daysOfWeek.length * 8;
  bytesCount += 3 + object.description.length * 3;
  {
    final value = object.scheduledTime;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  bytesCount += 3 + object.title.length * 3;
  bytesCount += 3 + object.type.length * 3;
  bytesCount += 3 + object.userId.length * 3;
  return bytesCount;
}

void _recoveryTaskSerialize(
  RecoveryTask object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeLongList(offsets[0], object.daysOfWeek);
  writer.writeString(offsets[1], object.description);
  writer.writeLong(offsets[2], object.durationDays);
  writer.writeBool(offsets[3], object.isSynced);
  writer.writeLong(offsets[4], object.planId);
  writer.writeString(offsets[5], object.scheduledTime);
  writer.writeDateTime(offsets[6], object.startDate);
  writer.writeString(offsets[7], object.title);
  writer.writeString(offsets[8], object.type);
  writer.writeString(offsets[9], object.userId);
}

